import hashlib, os
def create_hash(file):  
    sha = hashlib.sha256() # or other appropriate algorithm here    
    with open ( file , 'rb' ) as f : 
        block = f.read(1024)        
        while len(block) > 0:            
            sha.update(block)             
            block = f.read(1024)     
          
    return sha.hexdigest()   # returns a hexadecimal digest of the SHA-256 hash value